(function() {
  const extractedStories = [];
  const titleRows = document.querySelectorAll('a.titlelink');

  for (let i = 0; i < Math.min(10, titleRows.length); i++) {
    const titleEl = titleRows[i];
    const titleRow = titleEl.closest('tr');
    const title = titleEl.innerText;
    const url = titleEl.href;

    // Find the metadata row (next table row after the title row)
    let metadataRow = titleRow.nextElementSibling;
    while (metadataRow && metadataRow.tagName !== 'TR') {
      metadataRow = metadataRow.nextElementSibling;
    }

    let score = 0;
    let author = '';
    let age = '';
    let comments = 0;

    if (metadataRow) {
      const scoreEl = metadataRow.querySelector('.score');
      if (scoreEl) {
        score = parseInt(scoreEl.innerText) || 0;
      }

      const links = metadataRow.querySelectorAll('a');
      for (let j = 0; j < links.length; j++) {
        const link = links[j];
        const href = link.href;

        if (href.includes('user?id=')) {
          author = link.innerText;
        } else if (href.includes('item?id=') && link.classList.contains('age')) {
          age = link.innerText;
        } else if (href.includes('item?id=') && link.innerText.includes('comment')) {
          comments = parseInt(link.innerText) || 0;
        }
      }
    }

    extractedStories.push({
      rank: i + 1,
      title: title,
      url: url,
      score: score,
      author: author,
      comments_count: comments,
      age: age
    });
  }

  return JSON.stringify(extractedStories, null, 2);
})()

(function() {
  const storiesData = [];
  const rows = Array.from(document.querySelectorAll('tr'));

  for (let i = 0; i < rows.length; i++) {
    const titleLink = rows[i].querySelector('a.titlelink');
    if (titleLink) {
      // Found a title row
      const title = titleLink.textContent.trim();
      const url = titleLink.href;

      // Metadata should be in the next row
      const nextRow = rows[i + 1];
      if (!nextRow) continue;

      const scoreText = nextRow.querySelector('.score')?.textContent || '';
      const score = parseInt(scoreText) || 0;

      const authorLink = nextRow.querySelector('a[href*="user?id"]');
      const author = authorLink?.textContent.trim() || '';

      const ageLink = nextRow.querySelector('a.age');
      const age = ageLink?.textContent.trim() || '';

      let commentsText = '';
      const links = nextRow.querySelectorAll('a');
      for (const link of links) {
        if (link.href.includes('item?id') && link.textContent.includes('comment')) {
          commentsText = link.textContent;
          break;
        }
      }
      const comments = parseInt(commentsText) || 0;

      storiesData.push({
        rank: storiesData.length + 1,
        title,
        url,
        score,
        author,
        comments_count: comments,
        age
      });

      if (storiesData.length === 10) break;
    }
  }

  return JSON.stringify(storiesData, null, 2);
})()

(function() {
  const stories = [];
  const titleLines = document.querySelectorAll('span.titleline');

  for (let i = 0; i < Math.min(10, titleLines.length); i++) {
    const titleLine = titleLines[i];
    const titleLink = titleLine.querySelector('a');
    if (!titleLink) continue;

    const title = titleLink.textContent.trim();
    const url = titleLink.href;

    // Find the metadata row - it's in a <tr> with class "subtext"
    let metaRow = titleLine.closest('tr').nextElementSibling;
    while (metaRow && !metaRow.classList.contains('subtext')) {
      metaRow = metaRow.nextElementSibling;
    }

    let score = 0, author = '', age = '', comments = 0;

    if (metaRow) {
      const scoreEl = metaRow.querySelector('.score');
      if (scoreEl) score = parseInt(scoreEl.textContent) || 0;

      const userLink = metaRow.querySelector('a[href*="user?id"]');
      if (userLink) author = userLink.textContent.trim();

      const ageLink = metaRow.querySelector('a[href*="item?id"]');
      if (ageLink && ageLink.classList.contains('age')) age = ageLink.textContent.trim();

      const allLinks = metaRow.querySelectorAll('a');
      for (const link of allLinks) {
        if (link.href.includes('item?id') && !link.classList.contains('age')) {
          const text = link.textContent.trim();
          if (text.includes('comment')) {
            comments = parseInt(text) || 0;
            break;
          }
        }
      }
    }

    stories.push({
      rank: i + 1,
      title,
      url,
      score,
      author,
      comments_count: comments,
      age
    });
  }

  return JSON.stringify(stories, null, 2);
})()

(function() {
  const stories = [];
  const titleLines = document.querySelectorAll('span.titleline');

  for (let i = 0; i < Math.min(10, titleLines.length); i++) {
    const titleLine = titleLines[i];
    const titleLink = titleLine.querySelector('a');
    if (!titleLink) continue;

    const title = titleLink.textContent.trim();
    const url = titleLink.href;

    // Get the parent row, then find subtext row
    const titleRow = titleLine.closest('tr');
    let metaRow = titleRow.parentElement.querySelector('tr.subtext');

    // Find the correct subtext row - it should follow this title
    let currentRow = titleRow;
    while (currentRow) {
      currentRow = currentRow.nextElementSibling;
      if (currentRow && currentRow.classList.contains('subtext')) {
        // Check if this subtext is for our story
        const nextTitle = currentRow.nextElementSibling?.querySelector('span.titleline');
        if (!nextTitle || nextTitle === titleLine) {
          metaRow = currentRow;
          break;
        }
      }
    }

    let score = 0, author = '', age = '', comments = 0;

    if (metaRow) {
      const scoreEl = metaRow.querySelector('.score');
      if (scoreEl) score = parseInt(scoreEl.textContent) || 0;

      const userLink = metaRow.querySelector('a[href*="user?id"]');
      if (userLink) author = userLink.textContent.trim();

      const allLinks = metaRow.querySelectorAll('a');
      for (const link of allLinks) {
        const href = link.href;
        const text = link.textContent.trim();

        if (href.includes('item?id') && text.includes('comment')) {
          comments = parseInt(text) || 0;
        } else if (text.match(/^\d+ .*ago$/)) {
          age = text;
        }
      }
    }

    stories.push({
      rank: i + 1,
      title,
      url,
      score,
      author,
      comments_count: comments,
      age
    });
  }

  return JSON.stringify(stories, null, 2);
})()

