(function extractStories() {
  const stories = [];
  const rows = document.querySelectorAll('table.itemlist > tbody > tr');

  for (let i = 0; i < rows.length && stories.length < 10; i++) {
    const row = rows[i];
    const titleEl = row.querySelector('span.titleline > a');

    if (!titleEl) continue;

    const title = titleEl.textContent.trim();
    const url = titleEl.href;

    // Find the subtext row (next row with metadata)
    let subRow = row.nextElementSibling;
    while (subRow && !subRow.querySelector('.subtext')) {
      subRow = subRow.nextElementSibling;
    }

    let score = 0, author = '', age = '', comments = 0;

    if (subRow) {
      const scoreEl = subRow.querySelector('.score');
      if (scoreEl) {
        const scoreText = scoreEl.textContent;
        score = parseInt(scoreText) || 0;
      }

      const userLink = subRow.querySelector('a[href^="user?id"]');
      if (userLink) {
        author = userLink.textContent.trim();
      }

      const ageEl = subRow.querySelector('a.age');
      if (ageEl) {
        age = ageEl.textContent.trim();
      }

      // Find comments count
      const allLinks = subRow.querySelectorAll('a');
      for (const link of allLinks) {
        const text = link.textContent.trim();
        if (text.includes('comment')) {
          comments = parseInt(text) || 0;
          break;
        }
      }
    }

    stories.push({
      rank: stories.length + 1,
      title,
      url,
      score,
      author,
      comments_count: comments,
      age
    });
  }

  return JSON.stringify(stories);
})()

(function() {
