(function extractTopStories() {
  const stories = [];
  const athingRows = document.querySelectorAll('tr.athing');

  for (let i = 0; i < Math.min(10, athingRows.length); i++) {
    const row = athingRows[i];
    const titleLink = row.querySelector('span.titleline a');

    if (!titleLink) continue;

    const title = titleLink.textContent.trim();
    const url = titleLink.href;

    // Metadata is in the next row after the athing row
    let nextRow = row.nextElementSibling;
    while (nextRow && !nextRow.querySelector('.score')) {
      nextRow = nextRow.nextElementSibling;
    }

    let score = 0, author = '', age = '', comments = 0;

    if (nextRow) {
      const scoreEl = nextRow.querySelector('.score');
      if (scoreEl) {
        const scoreText = scoreEl.textContent.trim();
        score = parseInt(scoreText) || 0;
      }

      const userLink = nextRow.querySelector('a[href*="user?id"]');
      if (userLink) {
        author = userLink.textContent.trim();
      }

      const allLinks = nextRow.querySelectorAll('a');
      for (const link of allLinks) {
        const href = link.getAttribute('href') || '';
        const text = link.textContent.trim();

        if (text.endsWith('ago') && href.includes('item?id')) {
          age = text;
        } else if (text.includes('comment')) {
          comments = parseInt(text) || 0;
        }
      }
    }

    stories.push({
      rank: i + 1,
      title,
      url,
      score,
      author,
      comments_count: comments,
      age
    });
  }

  return JSON.stringify(stories, null, 2);
})()

