(function() {
  const data = [];

  // Look for the main result containers - they typically have a specific structure
  const results = document.querySelectorAll('div[jsname], a[href*="http"]');
  const processed = new Set();

  document.querySelectorAll('h3').forEach((h3, idx) => {
    if (idx >= 5 || processed.size >= 5) return;

    const title = h3.textContent.trim();

    // Find the enclosing result div
    let resultDiv = h3.parentElement;
    for (let i = 0; i < 10; i++) {
      if (!resultDiv) break;
      const link = resultDiv.querySelector('a[href^="http"]');
      if (link) {
        const url = link.href;

        // Skip if already processed
        if (processed.has(url)) break;

        // Find description - usually in a specific div pattern
        let desc = '';
        const possibleDescs = resultDiv.querySelectorAll('div > span, div[style], .st, .s');
        for (let el of possibleDescs) {
          const text = el.textContent.trim();
          if (text.length > 30 && text.length < 300) {
            desc = text;
            break;
          }
        }

        data.push({
          title: title,
          url: url,
          description: desc
        });
        processed.add(url);
        break;
      }
      resultDiv = resultDiv.parentElement;
    }
  });

  return JSON.stringify(data.slice(0, 5), null, 2);
})()

