(function() {
  const data = [];

  document.querySelectorAll('h3').forEach((h3, idx) => {
    if (idx >= 5 || data.length >= 5) return;

    const title = h3.textContent.trim();

    // Navigate up to find the result container
    let container = h3.closest('[data-sokoban-container]') || h3.closest('div[jsaction]') || h3.parentElement.parentElement.parentElement;
    if (!container) return;

    const link = container.querySelector('a[href^="http"]');
    if (!link) return;

    const url = link.href;

    // The description is usually after the citation info
    let desc = '';
    const allText = container.innerText;
    const lines = allText.split('\n');

    // Find lines that look like descriptions (not URLs, not "Translate", etc)
    for (let line of lines) {
      const trimmed = line.trim();
      if (trimmed.length > 30 && 
          trimmed.length < 300 && 
          !trimmed.includes('http') &&
          !trimmed.includes('Translate') &&
          !trimmed.includes('www.') &&
          !trimmed.startsWith('›')) {
        desc = trimmed;
        break;
      }
    }

    data.push({ title, url, description: desc });
  });

  return JSON.stringify(data, null, 2);
})()

